// Parse Google SERP WITHOUT cheerio — using regex only
const html = $input.first().json.body || $input.first().json.data || '';
const keyword = $node.Webhook.json.body.keyword;
const analysis_id = $node.Webhook.json.body.analysis_id;
const callback_url = $node.Webhook.json.body.callback_url;

// Extract organic results using regex
const results = [];
const linkRegex = /<a[^>]+href="(https?:\/\/[^"]+)"[^>]*>.*?<h3[^>]*>(.*?)<\/h3>/gs;
let match;
while ((match = linkRegex.exec(html)) !== null && results.length < 10) {
  const url = match[1];
  const title = match[2].replace(/<[^>]+>/g, '').trim();
  if (url && !url.includes('google.com') && !url.includes('youtube.com/results')) {
    try {
      results.push({
        position: results.length + 1,
        url: url,
        title: title,
        domain: new URL(url).hostname
      });
    } catch(e) {}
  }
}

// Fallback: try another pattern if first didn't work
if (results.length === 0) {
  const altRegex = /href="(https?:\/\/(?!www\.google)[^"]{20,})"[^>]*>[^<]*<[^>]*>([^<]{5,})</g;
  while ((match = altRegex.exec(html)) !== null && results.length < 10) {
    try {
      const url = match[1];
      results.push({
        position: results.length + 1,
        url: url,
        title: match[2].trim(),
        domain: new URL(url).hostname
      });
    } catch(e) {}
  }
}

// Extract People Also Ask questions
const questions = [];
const paaRegex = /data-q="([^"]+)"/g;
while ((match = paaRegex.exec(html)) !== null) {
  questions.push(match[1]);
}

return [{json: {results, questions, keyword, analysis_id, callback_url}}];

// Extract page data WITHOUT cheerio
const html = $input.first().json.body || $input.first().json.data || '';
const pos = $input.first().json.position || 0;
const url = $input.first().json.url || '';
const domain = $input.first().json.domain || '';
const title = $input.first().json.title || '';

// Remove script/style tags
const clean = html.replace(/<script[^>]*>[\s\S]*?<\/script>/gi, '')
                   .replace(/<style[^>]*>[\s\S]*?<\/style>/gi, '')
                   .replace(/<nav[^>]*>[\s\S]*?<\/nav>/gi, '')
                   .replace(/<footer[^>]*>[\s\S]*?<\/footer>/gi, '');

// Extract headings
const h1s = [...(clean.matchAll(/<h1[^>]*>(.*?)<\/h1>/gi))].map(m => m[1].replace(/<[^>]+>/g,'').trim());
const h2s = [...(clean.matchAll(/<h2[^>]*>(.*?)<\/h2>/gi))].map(m => m[1].replace(/<[^>]+>/g,'').trim());
const h3s = [...(clean.matchAll(/<h3[^>]*>(.*?)<\/h3>/gi))].map(m => m[1].replace(/<[^>]+>/g,'').trim());

// Get text content and word count
const text = clean.replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim();
const words = text.split(/[\s\u200C]+/).filter(w => w.length > 1);

// Extract Persian keywords
const stops = new Set(['و','در','به','از','که','این','را','با','است','آن','یک','برای','تا','ها','های','می','شود','کرد','شده','بود','هم']);
const persianWords = text.match(/[\u0600-\u06FF\u200C]{3,}/g) || [];
const freq = {};
persianWords.forEach(w => {
  const n = w.toLowerCase().replace(/\u200C{2,}/g, '\u200C');
  if (!stops.has(n)) freq[n] = (freq[n] || 0) + 1;
});
const topKw = Object.entries(freq).sort((a,b) => b[1]-a[1]).slice(0, 30).map(e => e[0]);

// Count images
const images = (html.match(/<img /gi) || []).length;

return [{json: {
  position: pos, url, domain, title,
  word_count: words.length,
  h1_count: h1s.length, h2_count: h2s.length, h3_count: h3s.length,
  headings: {h1: h1s.slice(0,3), h2: h2s.slice(0,10), h3: h3s.slice(0,10)},
  images, schema_types: '',
  top_keywords: topKw
}}];

const comps = $input.all().map(i => i.json);
const meta = $node['Parse SERP'].json;
const n = comps.length || 1;

const avgW = Math.round(comps.reduce((s,c) => s + (c.word_count||0), 0) / n);
const avgH = Math.round(comps.reduce((s,c) => s + (c.h1_count||0) + (c.h2_count||0) + (c.h3_count||0), 0) / n);

// LSI keywords (appear in 2+ pages)
const kwC = {};
comps.forEach(c => (c.top_keywords||[]).forEach(k => { kwC[k] = (kwC[k]||0) + 1; }));
const lsi = Object.entries(kwC).filter(e => e[1] >= 2).sort((a,b) => b[1]-a[1]).slice(0, 30).map(e => e[0]);

// Content gap (H2 topics in 2+ pages)
const h2T = {};
comps.forEach(c => (c.headings?.h2||[]).forEach(h => {
  const n2 = h.toLowerCase().trim();
  if (n2.length > 5) h2T[n2] = (h2T[n2]||0) + 1;
}));
const gap = Object.entries(h2T).filter(e => e[1] >= 2).sort((a,b) => b[1]-a[1]).slice(0, 15).map(e => e[0]);

return [{json: {
  analysis_id: meta.analysis_id,
  callback_url: meta.callback_url,
  avg_word_count: avgW,
  avg_headings: avgH,
  lsi_keywords: lsi,
  content_gap: gap,
  questions: meta.questions || [],
  competitors: comps
}}];
